
package com.example.taxgap.domain.entity; import jakarta.persistence.*; import java.util.Set;
@Entity @Table(name="users")
public class User { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(unique=true, nullable=false) private String username; @Column(nullable=false) private String password; private boolean enabled=true; @ManyToMany(fetch=FetchType.EAGER) @JoinTable(name="users_roles", joinColumns=@JoinColumn(name="user_id"), inverseJoinColumns=@JoinColumn(name="role_id")) private Set<Role> roles; public Long getId(){return id;} public void setId(Long v){id=v;} public String getUsername(){return username;} public void setUsername(String v){username=v;} public String getPassword(){return password;} public void setPassword(String v){password=v;} public boolean isEnabled(){return enabled;} public void setEnabled(boolean v){enabled=v;} public Set<Role> getRoles(){return roles;} public void setRoles(Set<Role> v){roles=v;} }
